1	#!/usr/bin/env node
2	
3	'use strict';
4	
5	const fs = require('fs');
6	const path = require('path');
7	const os = require('os');
8	const { execSync } = require('child_process');
9	
10	const PKG_ROOT = path.resolve(__dirname, '..');
11	const CWD = process.cwd();
12	const VERSION = require(path.join(PKG_ROOT, 'package.json')).version;
13	
14	const { detectPlatforms, getSummary } = require(path.join(PKG_ROOT, 'lib', 'platform-detect'));
15	
16	// --- Helpers ---
17	
18	function warn(msg) {
19	  console.log(`  \u26a0  ${msg}`);
20	}
21	
22	function info(msg) {
23	  console.log(`  \u2713  ${msg}`);
24	}
25	
26	function skip(msg) {
27	  console.log(`  \u00b7  ${msg} (already exists, skipped)`);
28	}
29	
30	function mkdirp(dir) {
31	  fs.mkdirSync(dir, { recursive: true });
32	}
33	
34	const METASWARM_MARKER = '## metaswarm';
35	
36	// --- Platform-specific install functions ---
37	
38	function installClaude() {
39	  console.log('\n  Installing for Claude Code...\n');
40	  try {
41	    console.log('  Running: claude plugin marketplace add dsifry/metaswarm-marketplace');
42	    execSync('claude plugin marketplace add dsifry/metaswarm-marketplace', { stdio: 'inherit' });
43	    console.log('  Running: claude plugin install metaswarm');
44	    execSync('claude plugin install metaswarm', { stdio: 'inherit' });
45	    info('Claude Code plugin installed');
46	    console.log('  Next: Open Claude Code and run /setup');
47	  } catch (e) {
48	    warn(`Claude Code install failed: ${e.message}`);
49	    console.log('  Try manually:');
50	    console.log('    claude plugin marketplace add dsifry/metaswarm-marketplace');
51	    console.log('    claude plugin install metaswarm');
52	  }
53	}
54	
55	function installCodex() {
56	  console.log('\n  Installing for Codex CLI...\n');
57	  const installDir = path.join(process.env.CODEX_HOME || path.join(os.homedir(), '.codex'), 'metaswarm');
58	  const skillsDir = path.join(os.homedir(), '.agents', 'skills');
59	
60	  if (fs.existsSync(installDir)) {
61	    console.log(`  Updating existing installation at ${installDir}...`);
62	    try {
63	      execSync('git pull --rebase origin main', { cwd: installDir, stdio: 'inherit' });
64	      info('Updated metaswarm');
65	    } catch (e) {
66	      warn(`git pull failed: ${e.message || e}`);
67	      return;
68	    }
69	  } else {
70	    console.log(`  Cloning metaswarm to ${installDir}...`);
71	    mkdirp(path.dirname(installDir));
72	    try {
73	      execSync(`git clone https://github.com/dsifry/metaswarm.git "${installDir}"`, { stdio: 'inherit' });
74	      info('Cloned metaswarm');
75	    } catch (e) {
76	      warn(`Clone failed: ${e.message}`);
77	      return;
78	    }
79	  }
80	
81	  // Symlink skills
82	  mkdirp(skillsDir);
83	  const skillsPath = path.join(installDir, 'skills');
84	  if (fs.existsSync(skillsPath)) {
85	    let linked = 0;
86	    for (const dir of fs.readdirSync(skillsPath)) {
87	      const srcDir = path.join(skillsPath, dir);
88	      if (!fs.statSync(srcDir).isDirectory()) continue;
89	      const linkName = `metaswarm-${dir}`;
90	      const linkPath = path.join(skillsDir, linkName);
91	
92	      try {
93	        if (fs.lstatSync(linkPath).isSymbolicLink()) {
94	          fs.unlinkSync(linkPath);
95	        } else if (fs.existsSync(linkPath)) {
96	          warn(`${linkPath} exists as a directory, skipping`);
97	          continue;
98	        }
99	      } catch (e) {
100	        if (e.code !== 'ENOENT') warn(`Unexpected error checking ${linkPath}: ${e.message}`);
101	      }
102	
103	      fs.symlinkSync(srcDir, linkPath);
104	      linked++;
105	    }
106	    info(`Linked ${linked} skills into ${skillsDir}`);
107	  }
108	  console.log('  Next: In your project, run $setup');
109	}
110	
111	function installGemini() {
112	  console.log('\n  Installing for Gemini CLI...\n');
113	  try {
114	    console.log('  Running: gemini extensions install https://github.com/dsifry/metaswarm.git');
115	    execSync('gemini extensions install https://github.com/dsifry/metaswarm.git', { stdio: 'inherit' });
116	    info('Gemini CLI extension installed');
117	    console.log('  Next: In your project, run /metaswarm:setup');
118	  } catch (e) {
119	    warn(`Gemini CLI install failed: ${e.message}`);
120	    console.log('  Try manually:');
121	    console.log('    gemini extensions install https://github.com/dsifry/metaswarm.git');
122	  }
123	}
124	
125	// --- Project-level setup ---
126	
127	function setupProject(platformFlag) {
128	  console.log(`\nmetaswarm v${VERSION} — project setup\n`);
129	
130	  const platforms = detectPlatforms();
131	  const targetPlatforms = [];
132	
133	  if (platformFlag === 'all') {
134	    // Explicit --all: target all platforms regardless of install status
135	    targetPlatforms.push('claude', 'codex', 'gemini');
136	  } else if (!platformFlag) {
137	    // No flag: auto-detect which are installed
138	    for (const [key, p] of Object.entries(platforms)) {
139	      if (p.installed) targetPlatforms.push(key);
140	    }
141	    if (targetPlatforms.length === 0) {
142	      targetPlatforms.push('claude'); // default
143	    }
144	  } else {
145	    targetPlatforms.push(platformFlag);
146	  }
147	
148	  console.log(`  Setting up for: ${targetPlatforms.join(', ')}\n`);
149	
150	  for (const plat of targetPlatforms) {
151	    const p = platforms[plat];
152	    const instrFile = p.instructionFile;
153	    const instrPath = path.join(CWD, instrFile);
154	    const templateDir = path.join(PKG_ROOT, 'templates');
155	    const fullTemplate = path.join(templateDir, instrFile);
156	    const appendTemplate = path.join(templateDir, `${path.basename(instrFile, '.md')}-append.md`);
157	
158	    if (!fs.existsSync(instrPath)) {
159	      if (fs.existsSync(fullTemplate)) {
160	        fs.copyFileSync(fullTemplate, instrPath);
161	        info(`${instrFile} (written from template)`);
162	      } else {
163	        warn(`${instrFile} template not found`);
164	      }
165	    } else {
166	      const existing = fs.readFileSync(instrPath, 'utf-8');
167	      if (existing.includes(METASWARM_MARKER) || existing.includes('metaswarm')) {
168	        skip(`${instrFile} (metaswarm reference already present)`);
169	      } else if (fs.existsSync(appendTemplate)) {
170	        fs.appendFileSync(instrPath, '\n' + fs.readFileSync(appendTemplate, 'utf-8'));
171	        info(`${instrFile} (appended metaswarm section)`);
172	      }
173	    }
174	  }
175	
176	  // Coverage thresholds
177	  const coveragePath = path.join(CWD, '.coverage-thresholds.json');
178	  const coverageTemplate = path.join(PKG_ROOT, 'templates', 'coverage-thresholds.json');
179	  if (!fs.existsSync(coveragePath) && fs.existsSync(coverageTemplate)) {
180	    fs.copyFileSync(coverageTemplate, coveragePath);
181	    info('.coverage-thresholds.json');
182	  } else if (fs.existsSync(coveragePath)) {
183	    skip('.coverage-thresholds.json');
184	  }
185	
186	  console.log('\n  Project setup complete!');
187	  for (const plat of targetPlatforms) {
188	    const p = platforms[plat];
189	    console.log(`  ${p.name}: Run ${p.setupCommand} for full interactive configuration`);
190	  }
191	  console.log('');
192	}
193	
194	// --- Commands ---
195	
196	function printHelp() {
197	  console.log(`
198	metaswarm v${VERSION} — Cross-platform installer
199	
200	Usage:
201	  metaswarm init [flags]        Install metaswarm for detected CLI tools
202	  metaswarm setup [flags]       Set up metaswarm in the current project
203	  metaswarm detect              Show which CLI tools are installed
204	  metaswarm --help              Show this help
205	  metaswarm --version           Show version
206	
207	Init flags:
208	  --claude            Install for Claude Code only
209	  --codex             Install for Codex CLI only
210	  --gemini            Install for Gemini CLI only
211	  (no flag)           Auto-detect installed CLIs and install for all
212	
213	Setup flags:
214	  --claude            Write CLAUDE.md only
215	  --codex             Write AGENTS.md only
216	  --gemini            Write GEMINI.md only
217	  --all               Write instruction files for all platforms
218	  (no flag)           Auto-detect installed CLIs
219	
220	Examples:
221	  npx metaswarm init            Auto-detect and install for all CLIs
222	  npx metaswarm init --codex    Install for Codex CLI only
223	  npx metaswarm setup           Set up project for detected CLIs
224	  npx metaswarm detect          Show which CLIs are available
225	`);
226	}
227	
228	async function initCommand(args) {
229	  const flags = new Set(args);
230	  const platforms = detectPlatforms();
231	
232	  console.log(`\nmetaswarm v${VERSION} — init\n`);
233	  console.log('  Detected CLI tools:\n');
234	  console.log(getSummary(platforms));
235	  console.log('');
236	
237	  // Determine which platforms to install for
238	  const explicit = flags.has('--claude') || flags.has('--codex') || flags.has('--gemini');
239	
240	  if (flags.has('--claude') || (!explicit && platforms.claude.installed)) {
241	    installClaude();
242	  }
243	
244	  if (flags.has('--codex') || (!explicit && platforms.codex.installed)) {
245	    installCodex();
246	  }
247	
248	  if (flags.has('--gemini') || (!explicit && platforms.gemini.installed)) {
249	    installGemini();
250	  }
251	
252	  if (!explicit) {
253	    const installed = Object.values(platforms).filter(p => p.installed);
254	    if (installed.length === 0) {
255	      console.log('\n  No supported CLI tools detected.');
256	      console.log('  Install one of: claude, codex, gemini');
257	      console.log('  Then re-run: npx metaswarm init\n');
258	    }
259	  }
260	
261	  console.log('\n  Init complete! Next: run `npx metaswarm setup` in your project.\n');
262	}
263	
264	function detectCommand() {
265	  const platforms = detectPlatforms();
266	  console.log(`\nmetaswarm v${VERSION} — platform detection\n`);
267	  console.log(getSummary(platforms));
268	  console.log('');
269	
270	  const installed = Object.entries(platforms).filter(([, p]) => p.installed);
271	  if (installed.length > 0) {
272	    console.log('  Install metaswarm:');
273	    for (const [, p] of installed) {
274	      console.log(`    ${p.name}: ${p.installCommand}`);
275	    }
276	  }
277	  console.log('');
278	}
279	
280	// --- Main ---
281	
282	const args = process.argv.slice(2);
283	const cmd = args[0];
284	
285	if (cmd === 'init') {
286	  initCommand(args.slice(1));
287	} else if (cmd === 'setup') {
288	  const flags = new Set(args.slice(1));
289	  let platformFlag = null;
290	  if (flags.has('--claude')) platformFlag = 'claude';
291	  else if (flags.has('--codex')) platformFlag = 'codex';
292	  else if (flags.has('--gemini')) platformFlag = 'gemini';
293	  else if (flags.has('--all')) platformFlag = 'all';
294	  setupProject(platformFlag);
295	} else if (cmd === 'detect') {
296	  detectCommand();
297	} else if (cmd === '--version' || cmd === '-v') {
298	  console.log(VERSION);
299	} else {
300	  printHelp();
301	}
